import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import type { ForwardedRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './List.module.css';

type ListMarker = 'disc' | 'decimal' | 'none';
type ListGap = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl';
type ListSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type ListTone = 'default' | 'muted' | 'subtle' | 'primary' | 'destructive';

type ListBaseProps = {
  marker?: ListMarker;
  gap?: ListGap;
  size?: ListSize;
  tone?: ListTone;
};
type ListRootProps =
  | (HTMLArkProps<'ul'> & ListBaseProps & { as?: 'ul' })
  | (HTMLArkProps<'ol'> & ListBaseProps & { as: 'ol' });

const ListRoot = forwardRef<HTMLUListElement | HTMLOListElement, ListRootProps>(function ListRoot(
  { as, asChild, className, gap = 'sm', marker, role, size = 'md', tone = 'default', ...props },
  ref,
) {
  const markerValue = marker ?? 'auto';
  const rootProps = {
    asChild,
    role: role ?? (markerValue === 'none' ? 'list' : undefined),
    ...props,
    'data-scope': 'list',
    'data-part': 'root',
    'data-slot': 'list-root',
    'data-gap': gap,
    'data-marker': markerValue,
    'data-size': size,
    'data-tone': tone,
    className: clsx(styles.root, normalizeClassName(className)),
  };

  if (as === 'ol') {
    return <ark.ol ref={ref as ForwardedRef<HTMLOListElement>} {...rootProps} />;
  }

  return <ark.ul ref={ref as ForwardedRef<HTMLUListElement>} {...rootProps} />;
});

const ListItem = forwardRef<HTMLLIElement, HTMLArkProps<'li'>>(function ListItem(
  { asChild, className, ...props },
  ref,
) {
  return (
    <ark.li
      ref={ref}
      asChild={asChild}
      {...props}
      data-scope="list"
      data-part="item"
      data-slot="list-item"
      className={normalizeClassName(className)}
    />
  );
});

const List = Object.assign(ListRoot, {
  Root: ListRoot,
  Item: ListItem,
});

export { List };

@layer moduix.components {
  .root[data-scope='list'][data-part='root'] {
    --_list-color: var(
      --moduix-list-color,
      var(--moduix-list-default-color, var(--moduix-color-foreground))
    );
    --_list-font-size: var(
      --moduix-list-font-size,
      var(--moduix-list-font-size-md, var(--moduix-text-md))
    );
    --_list-gap: var(--moduix-list-gap, var(--moduix-list-gap-sm, var(--moduix-spacing-2)));
    --_list-line-height: var(
      --moduix-list-line-height,
      var(--moduix-list-line-height-md, var(--moduix-line-height-text-md))
    );

    box-sizing: border-box;
    margin: 0;
    padding: 0;
    color: var(--_list-color);
    font-family: var(--moduix-list-font-family, inherit);
    font-size: var(--_list-font-size);
    font-weight: var(--moduix-list-font-weight, var(--moduix-weight-regular));
    line-height: var(--_list-line-height);
    letter-spacing: var(--moduix-list-letter-spacing, 0);
    list-style-position: outside;
    overflow-wrap: break-word;

    &[data-gap='xs'] {
      --_list-gap: var(--moduix-list-gap, var(--moduix-list-gap-xs, var(--moduix-spacing-1)));
    }

    &[data-gap='sm'] {
      --_list-gap: var(--moduix-list-gap, var(--moduix-list-gap-sm, var(--moduix-spacing-2)));
    }

    &[data-gap='md'] {
      --_list-gap: var(--moduix-list-gap, var(--moduix-list-gap-md, var(--moduix-spacing-3)));
    }

    &[data-gap='lg'] {
      --_list-gap: var(--moduix-list-gap, var(--moduix-list-gap-lg, var(--moduix-spacing-4)));
    }

    &[data-gap='xl'] {
      --_list-gap: var(--moduix-list-gap, var(--moduix-list-gap-xl, var(--moduix-spacing-5)));
    }

    &[data-gap='2xl'] {
      --_list-gap: var(--moduix-list-gap, var(--moduix-list-gap-2xl, var(--moduix-spacing-6)));
    }

    & > li + li {
      margin-block-start: var(--_list-gap);
    }

    & > li::marker {
      color: var(--moduix-list-marker-color, currentColor);
      font-weight: var(--moduix-list-marker-font-weight, inherit);
    }

    &[data-marker='none'] {
      padding-inline-start: 0;
      list-style: none;
    }

    &:is(ul, ol)[data-marker='auto'],
    &[data-marker='disc'],
    &[data-marker='decimal'] {
      padding-inline-start: var(--moduix-list-padding-x, var(--moduix-spacing-5));
    }

    &:is(ul)[data-marker='auto'],
    &[data-marker='disc'] {
      list-style-type: disc;
    }

    &:is(ol)[data-marker='auto'] {
      list-style-type: revert;
    }

    &:is(ul)[data-marker='decimal'],
    &:is(ol)[data-marker='decimal'] {
      list-style-type: decimal;
    }

    &[data-size='xs'] {
      --_list-font-size: var(
        --moduix-list-font-size,
        var(--moduix-list-font-size-xs, var(--moduix-text-xs))
      );
      --_list-line-height: var(
        --moduix-list-line-height,
        var(--moduix-list-line-height-xs, var(--moduix-line-height-text-xs))
      );
    }

    &[data-size='sm'] {
      --_list-font-size: var(
        --moduix-list-font-size,
        var(--moduix-list-font-size-sm, var(--moduix-text-sm))
      );
      --_list-line-height: var(
        --moduix-list-line-height,
        var(--moduix-list-line-height-sm, var(--moduix-line-height-text-sm))
      );
    }

    &[data-size='md'] {
      --_list-font-size: var(
        --moduix-list-font-size,
        var(--moduix-list-font-size-md, var(--moduix-text-md))
      );
      --_list-line-height: var(
        --moduix-list-line-height,
        var(--moduix-list-line-height-md, var(--moduix-line-height-text-md))
      );
    }

    &[data-size='lg'] {
      --_list-font-size: var(
        --moduix-list-font-size,
        var(--moduix-list-font-size-lg, var(--moduix-text-lg))
      );
      --_list-line-height: var(
        --moduix-list-line-height,
        var(--moduix-list-line-height-lg, var(--moduix-line-height-text-lg))
      );
    }

    &[data-size='xl'] {
      --_list-font-size: var(
        --moduix-list-font-size,
        var(--moduix-list-font-size-xl, var(--moduix-text-xl))
      );
      --_list-line-height: var(
        --moduix-list-line-height,
        var(--moduix-list-line-height-xl, var(--moduix-line-height-text-xl))
      );
    }

    &[data-tone='default'] {
      --_list-color: var(
        --moduix-list-color,
        var(--moduix-list-default-color, var(--moduix-color-foreground))
      );
    }

    &[data-tone='muted'] {
      --_list-color: var(
        --moduix-list-color,
        var(--moduix-list-muted-color, var(--moduix-color-muted-foreground))
      );
    }

    &[data-tone='subtle'] {
      --_list-color: var(
        --moduix-list-color,
        var(--moduix-list-subtle-color, var(--moduix-color-secondary-foreground))
      );
    }

    &[data-tone='primary'] {
      --_list-color: var(
        --moduix-list-color,
        var(--moduix-list-primary-color, var(--moduix-color-primary))
      );
    }

    &[data-tone='destructive'] {
      --_list-color: var(
        --moduix-list-color,
        var(--moduix-list-destructive-color, var(--moduix-color-destructive))
      );
    }
  }
}
